import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/network/chapter-5.md","filePath":"szu/network/chapter-5.md"}'),r={name:"szu/network/chapter-5.md"};function o(u,l,C,n,c,s){return a(),e("div",null,[...l[0]||(l[0]=[t('<h2 id="一-、数据链路层服务" tabindex="-1">(一)、数据链路层服务 <a class="header-anchor" href="#一-、数据链路层服务" aria-label="Permalink to &quot;(一)、数据链路层服务&quot;">​</a></h2><ol><li>数据链路层是 OSI 参考模型中的第二层，介乎于物理层和网络层提供的服务的基础上向网络层提供服务。</li><li>帧是数据链路层的传送单位 <ul><li>数据链路层将比特流组织成为帧为单位传送</li><li>若传输中发生差错，只需要将出错的有限数据进行重发</li></ul></li><li>数据链路层的服务：1.组帧（封装帧头帧尾）；2.链路接入；3.可靠交付；4.差错控制</li></ol><h2 id="二-、差错控制" tabindex="-1">(二)、差错控制 <a class="header-anchor" href="#二-、差错控制" aria-label="Permalink to &quot;(二)、差错控制&quot;">​</a></h2><ol><li>产生差错的原因：噪声 <ul><li>随机噪声、冲击噪声（如雷击）</li><li>突发长度：冲击噪声引起的差错，突发错误的第一位错误与最后一位错误之间的长度。</li></ul></li><li>差错控制基本方式 <ul><li>1.检错重发</li><li>2.前向纠错，适用于单工链路或实时性要求高</li><li>3.反馈校验</li><li>4.差错丢弃</li></ul></li><li>差错编码原理 <ul><li>差错编码的基本原理就是在待传输数据信息的基础上，附加一定的冗余信息，该冗余信息建立起数据信息的某种关联关系，将数据信息以及附加的冗余信息一同发送到接收端，接收端可以检测冗余信息表征的数据信息的关联关系是否存在，如果存在则没有错误，否则就有错误。</li></ul></li><li>差错编码的检错能力与纠错能力 <ul><li>汉明距离</li><li>循环冗余校验（CRC） <ul><li>因为奇偶校验率漏检率太高，因此采用漏检率低且方便实现的 CRC 校验。CRC 校验码又称为多项式编码</li><li>在数据链路层协议中广泛应用</li><li>生成码多项式及其算术运算</li><li>例如：C=1100101 C(x)=1x^6+1x^5+0x^4+0x^3+1x^2+0x^1+1x^0 = x^6 + x^5 + x^2 + 1</li></ul></li><li>循环冗余校验 CRC 码的生成</li><li>循环冗余校验 CRC 码的计算</li></ul></li></ol><h2 id="三-、多路由访问控制协议" tabindex="-1">(三)、多路由访问控制协议 <a class="header-anchor" href="#三-、多路由访问控制协议" aria-label="Permalink to &quot;(三)、多路由访问控制协议&quot;">​</a></h2><ol><li>计算机网络可以分成两类 <ul><li>点到点通信，例如广域网</li><li>广播通信，使用广播信道的网络，例如局域网</li></ul></li><li>广播网络的关键问题：如何解决<strong>信道争用</strong></li><li>解决信道争用的协议称为介质访问控制协议 MAC <ul><li>MAC 协议，是数据链路层协议的一部分</li><li>信道划分 MAC 协议 <ul><li>1.频分多路；2.时分多路；3.波分多路；4.码分多路复用。</li></ul></li><li>随机访问 MAC 协议 <ul><li>概念，就是所有用户都可以根据自己的意愿随机地向信道上发送信息。</li></ul></li><li>受控接入 MAC 协议</li></ul></li><li>随机访问 MAC 协议，早期版本是 ALOHA 协议 <ul><li>纯 ALOHA 协议</li><li>时隙 ALOHA 协议</li></ul></li><li>随机访问 MAC 协议，最常用的是载波侦听多路访问协议（CSMA）</li><li>CSMA 的四种监听方式 <ul><li>非坚持 CSMA</li><li>1-坚持 CSMA</li><li>p-坚持 CSMA</li><li>带有冲突检测的 CSMA/CD</li></ul></li><li>CSMD/CD 检测冲突时间的计算</li><li>最小帧长的计算</li><li>受控接入 MAC 协议</li></ol><h2 id="四-、局域网" tabindex="-1">(四)、局域网 <a class="header-anchor" href="#四-、局域网" aria-label="Permalink to &quot;(四)、局域网&quot;">​</a></h2><ol><li>IEEE802 标准是局域网的国际标准系列，由 ISO 采纳 <ul><li>数据链路层又分为逻辑链路控制 LLC 和介质访问控制 MAC 两个子层</li><li>实际上 LLC 层已几乎无用</li></ul></li><li>数据链路层寻址与 ARP <ul><li>IP--ARP--MAC</li></ul></li><li>MAC 地址格式 <ul><li>6 个字节 48bit，十六进制表示</li><li>MAC 地址具有唯一性</li><li>MAC 广播地址，48bit 全是 1，十六进制全是 6 个 FF</li></ul></li><li>ARP 表负责解析 IP 地址到 MAC 地址</li><li>以太网 Ethernet 代表有线局域网技术标准</li><li>以太网帧结构 <ul><li><img src="https://pica.zhimg.com/v2-35c88cade5950f3fc2e23d73df9619bc_1440w.jpg?source=172ae18b" alt="image"></li></ul></li><li>以太网技术</li><li>交换机是数据链路层的主要设备，也是以太网的主要网络设备</li><li>虚拟局域网</li></ol><h2 id="五-、点对点链路协议" tabindex="-1">(五)、点对点链路协议 <a class="header-anchor" href="#五-、点对点链路协议" aria-label="Permalink to &quot;(五)、点对点链路协议&quot;">​</a></h2><ol><li>PPP 协议</li><li>HDLC 协议</li></ol>',10)])])}const d=i(r,[["render",o]]);export{A as __pageData,d as default};
